"use client";

import * as React from "react";
import {
  ActionQueue,
  ApprovalSteps,
  Badge,
  BarChart,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  DataTable,
  Delta,
  LabeledDonutCard,
  Meter,
  PageHeader,
  SafetyBanner,
  Select,
  StackedBarChart,
  StatGroup,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  type ActionItem,
  type ChartDataPoint,
  type StatisticProps,
} from "@gunjo/ui";
import {
  IconAlertTriangle,
  IconClipboardList,
  IconDownload,
  IconFileText,
} from "@tabler/icons-react";
import { caseColumns } from "./columns";
import {
  actionItems,
  cases,
  depotRanking,
  kindBreakdown,
  kpis,
  monthlyTrend,
  reportFlow,
  routeHotspots,
  type SafetyCase,
} from "./data";

// 安全指標は「少ないほど良い・ゼロが目標」。
// rawDelta が負（=件数/率が減った）なら改善＝positive、増えたら negative。
// ヒヤリハット報告だけは “報告は多いほど健全” なので符号を反転する。
function kpiToStatistic(): StatisticProps[] {
  return kpis.map((k) => {
    const reportsAreGoodWhenHigh = k.label.startsWith("ヒヤリハット");
    const improved = reportsAreGoodWhenHigh ? k.rawDelta > 0 : k.rawDelta < 0;
    const worsened = reportsAreGoodWhenHigh ? k.rawDelta < 0 : k.rawDelta > 0;
    return {
      label: k.label,
      value: k.value,
      change: k.changeLabel,
      // trend は矢印の向き（実際の増減方向）。tone は良し悪し（色）。
      trend: k.rawDelta > 0 ? "up" : k.rawDelta < 0 ? "down" : "flat",
      tone: improved ? "positive" : worsened ? "negative" : "neutral",
      hint: k.hint,
    } satisfies StatisticProps;
  });
}

// 種別内訳（構成比ドーナツ）。多い順に並べ、注意色をあてる。
const kindSegments: ChartDataPoint[] = kindBreakdown.map((d) => ({
  label: d.label,
  value: d.value,
  color:
    d.label === "人身事故"
      ? "destructive"
      : d.label === "接触" || d.label === "車内事故"
        ? "warning"
        : d.label === "物損事故"
          ? "info"
          : "muted",
}));

// 月次推移（事故＋苦情の積み上げ）。
const trendGroups = monthlyTrend.map((m) => ({
  label: m.month,
  segments: [
    { label: "苦情", value: m.complaints, color: "info" as const },
    { label: "事故", value: m.accidents, color: "destructive" as const },
  ],
}));

// 系統別 多発（水平バーで件数ランキング）。
const routeBars: ChartDataPoint[] = routeHotspots.map((r, i) => ({
  label: `${r.route}`,
  value: r.count,
  color: i === 0 ? "destructive" : i === 1 ? "warning" : "info",
}));

const actionQueueItems: ActionItem[] = actionItems.map((a) => ({
  id: a.id,
  severity: a.severity,
  kind: a.kind,
  title: a.title,
  detail: a.detail,
  meta: a.meta,
}));

export default function BusSafetyConsolePage() {
  const [depotFilter, setDepotFilter] = React.useState<string>("all");
  const [selectedCase, setSelectedCase] = React.useState<SafetyCase | null>(null);

  const depots = React.useMemo(
    () => Array.from(new Set(cases.map((c) => c.depot))),
    [],
  );

  const filteredCases = React.useMemo(
    () =>
      depotFilter === "all"
        ? cases
        : cases.filter((c) => c.depot === depotFilter),
    [depotFilter],
  );

  const openCount = cases.filter(
    (c) => c.status === "速報" || c.status === "調査中",
  ).length;

  return (
    <div className="min-h-full bg-muted/30">
      <PageHeader
        title="運輸安全マネジメント コンソール"
        subtitle="青嶺交通株式会社 ／ 安全統括管理者 室長 — 2026年度 第1四半期"
        sticky
        leading={
          <div className="flex size-9 items-center justify-center rounded-lg bg-primary/10 text-primary">
            <IconClipboardList className="h-5 w-5" aria-hidden />
          </div>
        }
        actions={
          <div className="flex items-center gap-2">
            <Button variant="outline" size="sm">
              <IconDownload className="h-4 w-4" aria-hidden />
              月次安全報告を書き出し
            </Button>
            <Button size="sm">
              <IconFileText className="h-4 w-4" aria-hidden />
              事故報告書を起票
            </Button>
          </div>
        }
      />

      <main className="mx-auto w-full max-w-screen-2xl px-4 py-5 lg:px-6">
        {/* 重大事故の注意喚起バナー（行政報告期限つき） */}
        <SafetyBanner
          tone="destructive"
          title="重大事故 2件 — うち1件は運輸局への行政報告が期限間近（07/02）"
          className="mb-5"
          actions={
            <Button variant="outline" size="sm">
              対象案件を開く
            </Button>
          }
        >
          AC-2026-0408（人身事故・練馬営業所・系統 光02）は詳細報告書が安全統括管理者の承認待ちです。承認後、速やかに行政報告を行ってください。
        </SafetyBanner>

        {/* ── 安全KPIサマリ（少ないほど良い／ゼロ目標） ── */}
        <section aria-labelledby="kpi-heading" className="mb-6">
          <div className="mb-2 flex items-baseline justify-between">
            <h2 id="kpi-heading" className="text-sm font-semibold text-foreground">
              安全KPIサマリ
              <span className="ml-2 text-xs font-normal text-muted-foreground">
                前年同期比 ／ 安全指標は少ないほど良い
              </span>
            </h2>
            <span className="text-xs text-muted-foreground">
              走行実績 20.3 百万km（年度累計）
            </span>
          </div>
          <StatGroup items={kpiToStatistic()} cols={{ base: 2, md: 3, lg: 5 }} />
        </section>

        {/* ── メイン2カラム：左=ワークリスト＋分析、右=承認フロー＋要対応 ── */}
        <div className="grid grid-cols-1 gap-6 xl:grid-cols-[minmax(0,1fr)_360px]">
          {/* 左カラム */}
          <div className="min-w-0 space-y-6">
            <Tabs defaultValue="worklist">
              <TabsList>
                <TabsTrigger value="worklist">
                  事故・苦情ワークリスト
                </TabsTrigger>
                <TabsTrigger value="analysis">発生状況の分析</TabsTrigger>
                <TabsTrigger value="ranking">営業所別・系統別</TabsTrigger>
              </TabsList>

              {/* 事故・苦情ワークリスト */}
              <TabsContent value="worklist" className="mt-4">
                <Card>
                  <CardHeader>
                    <div className="flex flex-wrap items-center justify-between gap-3">
                      <div>
                        <CardTitle>事故・苦情ワークリスト</CardTitle>
                        <CardDescription>
                          直近の事故・インシデント・苦情。重大度の高い順にトリアージ（列見出しで並べ替え可）。
                          未クローズ {openCount} 件。
                        </CardDescription>
                      </div>
                      <div className="w-44">
                        <Select
                          aria-label="営業所で絞り込み"
                          value={depotFilter}
                          onChange={(e) => setDepotFilter(e.target.value)}
                        >
                          <option value="all">全営業所</option>
                          {depots.map((d) => (
                            <option key={d} value={d}>
                              {d}
                            </option>
                          ))}
                        </Select>
                      </div>
                    </div>
                  </CardHeader>
                  <CardContent>
                    <DataTable
                      columns={caseColumns}
                      data={filteredCases}
                      filter={{
                        columnId: "summary",
                        placeholder: "概要・受付番号で検索",
                      }}
                      pageSize={10}
                      onRowClick={(row) => setSelectedCase(row)}
                    />
                    {selectedCase ? (
                      <div
                        role="status"
                        className="mt-3 flex items-start gap-2 rounded-lg border border-info-border bg-info-subtle px-3 py-2 text-sm text-info-subtle-foreground"
                      >
                        <IconAlertTriangle
                          className="mt-0.5 h-4 w-4 shrink-0"
                          aria-hidden
                        />
                        <span>
                          選択中: <strong>{selectedCase.id}</strong> ／{" "}
                          {selectedCase.kind} ／ {selectedCase.depot} ／ 系統{" "}
                          {selectedCase.route} ／ {selectedCase.driver}
                          。詳細パネルを開いて報告書を確認してください。
                        </span>
                      </div>
                    ) : null}
                  </CardContent>
                </Card>
              </TabsContent>

              {/* 発生状況の分析 */}
              <TabsContent value="analysis" className="mt-4">
                <div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
                  <LabeledDonutCard
                    title="種別の内訳（当月）"
                    description="事故・苦情の構成比"
                    segments={kindSegments}
                    centerValue={String(
                      kindBreakdown.reduce((s, d) => s + d.value, 0),
                    )}
                    centerLabel="件"
                    totalLabel="合計"
                    formatValue={(v) => `${v}件`}
                  />
                  <Card>
                    <CardHeader>
                      <CardTitle>月次推移（事故＋苦情）</CardTitle>
                      <CardDescription>
                        6月は苦情・事故ともに増加傾向。梅雨期の路面状況に留意。
                      </CardDescription>
                    </CardHeader>
                    <CardContent>
                      <StackedBarChart
                        data={trendGroups}
                        variant="vertical"
                        showLegend
                        showValues
                        formatValue={(v) => `${v}件`}
                      />
                    </CardContent>
                  </Card>
                </div>
              </TabsContent>

              {/* 営業所別・系統別の安全指標ランキング */}
              <TabsContent value="ranking" className="mt-4">
                <div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
                  {/* 営業所別 事故率ランキング（要注意＝上位） */}
                  <Card>
                    <CardHeader>
                      <CardTitle>営業所別 安全指標</CardTitle>
                      <CardDescription>
                        走行百万kmあたり事故率（高いほど要注意）。先頭がワースト。
                      </CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-3">
                      {depotRanking.map((d, i) => (
                        <div key={d.depot}>
                          <div className="mb-1 flex items-center justify-between gap-2 text-sm">
                            <span className="flex items-center gap-2">
                              <span
                                className="inline-flex size-5 items-center justify-center rounded-full bg-secondary text-xs font-semibold tabular-nums text-secondary-foreground"
                                aria-hidden
                              >
                                {i + 1}
                              </span>
                              <span className="font-medium">{d.depot}</span>
                              {i === 0 ? (
                                <Badge variant="destructive">要注意</Badge>
                              ) : null}
                            </span>
                            <span className="flex items-center gap-2 tabular-nums">
                              <span className="font-semibold">{d.rate}</span>
                              <Delta
                                value={d.yoyDelta}
                                // 事故率は下がる(負)のが good。
                                tones={{
                                  positive: "destructive",
                                  negative: "success",
                                }}
                                format={(v) =>
                                  `${v > 0 ? "+" : ""}${v.toFixed(2)}`
                                }
                              />
                            </span>
                          </div>
                          <Meter
                            value={d.rate}
                            max={3}
                            direction="higher-is-worse"
                            thresholds={{ warning: 0.6, over: 0.8 }}
                            aria-label={`${d.depot} の事故率 ${d.rate}`}
                          />
                          <p className="mt-1 text-xs text-muted-foreground">
                            事故 {d.accidents}件・苦情 {d.complaints}件
                          </p>
                        </div>
                      ))}
                    </CardContent>
                  </Card>

                  {/* 系統別 多発（水平バー） */}
                  <Card>
                    <CardHeader>
                      <CardTitle>系統別 多発（直近90日）</CardTitle>
                      <CardDescription>
                        事故＋苦情の件数。渋88が突出 — 添乗指導・安全教育の重点系統。
                      </CardDescription>
                    </CardHeader>
                    <CardContent>
                      <BarChart
                        data={routeBars}
                        variant="horizontal"
                        showValues
                        showLabels
                        formatValue={(v) => `${v}件`}
                      />
                      <ul className="mt-3 space-y-1 text-xs text-muted-foreground">
                        {routeHotspots.map((r) => (
                          <li key={r.route} className="flex gap-2">
                            <span className="font-mono font-semibold text-foreground">
                              {r.route}
                            </span>
                            <span>{r.label}</span>
                          </li>
                        ))}
                      </ul>
                    </CardContent>
                  </Card>
                </div>
              </TabsContent>
            </Tabs>
          </div>

          {/* 右カラム：承認フロー＋要対応 */}
          <aside className="space-y-6">
            {/* 事故報告 → 承認 → 是正 → 水平展開 */}
            <Card>
              <CardHeader>
                <CardTitle>事故報告フロー</CardTitle>
                <CardDescription>
                  AC-2026-0408（人身・練馬・光02）速報 → 詳細報告 → 承認 → 再発防止 → 水平展開
                </CardDescription>
              </CardHeader>
              <CardContent>
                <ApprovalSteps
                  steps={reportFlow}
                  stateLabels={{
                    pending: "未着手",
                    current: "承認待ち",
                    approved: "完了",
                    rejected: "差戻し",
                    skipped: "対象外",
                  }}
                />
              </CardContent>
            </Card>

            {/* 要対応キュー（重大度順） */}
            <Card>
              <CardHeader>
                <div className="flex items-center justify-between">
                  <CardTitle>要対応</CardTitle>
                  <Badge variant="destructive">
                    {actionItems.filter((a) => a.severity === "critical").length}{" "}
                    緊急
                  </Badge>
                </div>
                <CardDescription>
                  未提出の報告・期限切れ間近の是正措置・多発系統・行政報告期限
                </CardDescription>
              </CardHeader>
              <CardContent>
                <ActionQueue
                  items={actionQueueItems}
                  emptyLabel="対応が必要な項目はありません"
                />
              </CardContent>
            </Card>
          </aside>
        </div>
      </main>
    </div>
  );
}

"use client";

import type { ColumnDef } from "@gunjo/ui";
import { Badge, Tag } from "@gunjo/ui";
import { IconVideo, IconVideoOff } from "@tabler/icons-react";
import type {
  CaseStatus,
  IncidentKind,
  Liability,
  SafetyCase,
  Severity,
} from "./data";

// 重大度の並び順（重大→中→軽微）。DataTable のソートで使う。
const SEVERITY_ORDER: Record<Severity, number> = { 重大: 0, 中: 1, 軽微: 2 };

const SEVERITY_VARIANT: Record<Severity, "destructive" | "warning" | "secondary"> = {
  重大: "destructive",
  中: "warning",
  軽微: "secondary",
};

const STATUS_VARIANT: Record<
  CaseStatus,
  "warning" | "info" | "secondary" | "success"
> = {
  速報: "warning",
  調査中: "info",
  報告済: "secondary",
  対策完了: "success",
};

const LIABILITY_VARIANT: Record<Liability, "destructive" | "outline" | "info" | "secondary"> = {
  有責: "destructive",
  無責: "outline",
  調査中: "info",
  "—": "secondary",
};

// 種別ごとの Tag バリアント（人身/接触＝注意色、苦情＝中立）。
const KIND_VARIANT: Record<IncidentKind, "destructive" | "default" | "outline"> = {
  人身事故: "destructive",
  接触: "outline",
  車内事故: "outline",
  物損事故: "outline",
  苦情: "default",
};

export const caseColumns: ColumnDef<SafetyCase>[] = [
  {
    accessorKey: "occurredAt",
    header: "発生日時",
    cell: ({ row }) => (
      <span className="whitespace-nowrap tabular-nums text-muted-foreground">
        {row.original.occurredAt}
      </span>
    ),
    size: 96,
  },
  {
    accessorKey: "severity",
    header: "重大度",
    // 重大→中→軽微 のドメイン順でソート（文字列の五十音順では崩れるため）。
    sortingFn: (a, b) =>
      SEVERITY_ORDER[a.original.severity] - SEVERITY_ORDER[b.original.severity],
    cell: ({ row }) => (
      <Badge variant={SEVERITY_VARIANT[row.original.severity]}>
        {row.original.severity}
      </Badge>
    ),
    size: 72,
  },
  {
    accessorKey: "kind",
    header: "種別",
    cell: ({ row }) => (
      <Tag variant={KIND_VARIANT[row.original.kind]}>{row.original.kind}</Tag>
    ),
    size: 88,
  },
  {
    accessorKey: "summary",
    header: "概要",
    cell: ({ row }) => (
      <div className="min-w-[220px] max-w-[420px]">
        <p className="line-clamp-2 text-foreground">{row.original.summary}</p>
        <p className="mt-0.5 font-mono text-[11px] text-muted-foreground">
          {row.original.id}
          {typeof row.original.injuries === "number" && row.original.injuries > 0
            ? ` ・ 負傷 ${row.original.injuries}名`
            : ""}
        </p>
      </div>
    ),
  },
  {
    accessorKey: "depot",
    header: "営業所",
    cell: ({ row }) => (
      <span className="whitespace-nowrap">{row.original.depot}</span>
    ),
    size: 104,
  },
  {
    accessorKey: "route",
    header: "系統",
    cell: ({ row }) => (
      <span className="inline-flex items-center rounded bg-secondary px-1.5 py-0.5 font-mono text-xs font-semibold text-secondary-foreground">
        {row.original.route}
      </span>
    ),
    size: 64,
  },
  {
    accessorKey: "driver",
    header: "運転士",
    cell: ({ row }) => (
      <span className="whitespace-nowrap">{row.original.driver}</span>
    ),
    size: 104,
  },
  {
    accessorKey: "liability",
    header: "責任",
    cell: ({ row }) => (
      <Badge variant={LIABILITY_VARIANT[row.original.liability]}>
        {row.original.liability}
      </Badge>
    ),
    size: 72,
  },
  {
    accessorKey: "status",
    header: "対応状況",
    cell: ({ row }) => (
      <Badge variant={STATUS_VARIANT[row.original.status]}>
        {row.original.status}
      </Badge>
    ),
    size: 88,
  },
  {
    id: "dr",
    header: "ドラレコ",
    enableSorting: false,
    cell: ({ row }) =>
      row.original.hasDriveRecorder ? (
        <span className="inline-flex items-center gap-1 text-success">
          <IconVideo className="h-4 w-4" aria-hidden />
          <span className="sr-only">ドライブレコーダー映像あり</span>
          <span aria-hidden className="text-xs">
            有
          </span>
        </span>
      ) : (
        <span className="inline-flex items-center gap-1 text-muted-foreground">
          <IconVideoOff className="h-4 w-4" aria-hidden />
          <span className="sr-only">ドライブレコーダー映像なし</span>
          <span aria-hidden className="text-xs">
            無
          </span>
        </span>
      ),
    size: 72,
  },
];

// 路線バス 運輸安全マネジメント・事故/苦情管理コンソール — ダミーデータ
// 架空の事業者「青嶺交通株式会社（あおみねこうつう）」を想定。
// すべて架空。系統・営業所・運転士名はそれらしく作った創作。

export type IncidentKind =
  | "人身事故"
  | "物損事故"
  | "車内事故" // 立ち客転倒など
  | "接触"
  | "苦情";

export type Liability = "有責" | "無責" | "調査中" | "—";

export type Severity = "重大" | "中" | "軽微";

export type CaseStatus = "速報" | "調査中" | "報告済" | "対策完了";

export interface SafetyCase {
  id: string; // 受付番号
  occurredAt: string; // 発生日時 ISO-ish 表示用
  kind: IncidentKind;
  depot: string; // 営業所
  route: string; // 系統
  driver: string; // 運転士
  liability: Liability; // 有責/無責
  severity: Severity; // 重大度
  status: CaseStatus; // 対応状況
  summary: string; // 概要
  hasDriveRecorder: boolean; // ドラレコ映像有無
  injuries?: number; // 負傷者数（人身/車内）
}

// ── 事故・苦情ワークリスト ───────────────────────────────────────────────
export const cases: SafetyCase[] = [
  {
    id: "AC-2026-0411",
    occurredAt: "06/27 08:12",
    kind: "車内事故",
    depot: "渋谷営業所",
    route: "渋88",
    driver: "佐久間 達也",
    liability: "有責",
    severity: "重大",
    status: "調査中",
    summary: "発車時の急加速で高齢の立ち客が転倒、頭部打撲で救急搬送（軽傷）。",
    hasDriveRecorder: true,
    injuries: 1,
  },
  {
    id: "AC-2026-0410",
    occurredAt: "06/27 07:48",
    kind: "接触",
    depot: "練馬営業所",
    route: "宿51",
    driver: "大野 さくら",
    liability: "調査中",
    severity: "中",
    status: "速報",
    summary: "右折時に自転車と接触のおそれ。相手に怪我なし、車体に擦過痕。ドラレコ確認中。",
    hasDriveRecorder: true,
  },
  {
    id: "CM-2026-1187",
    occurredAt: "06/26 19:30",
    kind: "苦情",
    depot: "渋谷営業所",
    route: "渋88",
    driver: "三宅 健一",
    liability: "—",
